where.if:
AND EXISTS (
  SELECT 1
  FROM build_generations generation_filter
  WHERE generation_filter.build_id = builds.id
    AND generation_filter.generation = #{generation}
)

mapper.select:
SELECT id, weapon_id AS weaponId, name, notes, sort_order AS sortOrder, is_favorite AS isFavorite, created_at AS createdAt, updated_at AS updatedAt FROM builds WHERE id IN
#{id}
ORDER BY sort_order ASC, updated_at DESC, id ASC

SELECT build_id AS ownerId, generation AS value FROM build_generations WHERE build_id IN
#{id}
ORDER BY build_id ASC, generation ASC

SELECT item.id, item.build_id AS buildId, item.slot, item.attachment_id AS attachmentId, item.created_at AS createdAt FROM build_items item INNER JOIN builds build ON build.id = item.build_id INNER JOIN weapon_slots weapon_slot ON weapon_slot.weapon_id = build.weapon_id AND weapon_slot.slot = item.slot WHERE item.build_id IN
#{id}
ORDER BY item.build_id ASC, weapon_slot.sort_order ASC, item.slot ASC
